/**
 * @summary Admin generates the fixed weekly recurring slots for the next N weeks
 */
export const generateRecurringSeancesBodySlotsItemDayMin = 0;
export const generateRecurringSeancesBodySlotsItemDayMax = 6;



export const GenerateRecurringSeancesBody = zod.object({
  "weeksAhead": zod.number().optional(),
  "slots": zod.array(zod.object({
  "day": zod.number().min(generateRecurringSeancesBodySlotsItemDayMin).max(generateRecurringSeancesBodySlotsItemDayMax),
  "time": zod.string().describe('HH:mm 24h time')
})).optional().describe('Optional custom weekly template. Each entry is one recurring slot (day of week + time). If omitted, the server falls back to its default fixed schedule. day uses JS Date.getDay() (0=Sunday..6=Saturday).')
})

export const GenerateRecurringSeancesResponse = zod.object({
  "success": zod.boolean(),
  "created": zod.number()
})


